package com.tuapp.clientesimport android.content.Intentimport android.os.Bundleimport androidx.appcompat.app.AppCompatActivityimport androidx.recyclerview.widget.LinearLayoutManagerimport androidx.recyclerview.widget.RecyclerViewimport com.google.android.material.floatingactionbutton.FloatingActionButtonclass MainActivity : AppCompatActivity() {    private lateinit var dbHelper: DatabaseHelper    private lateinit var adapter: CustomerAdapter    private lateinit var recyclerView: RecyclerView    override fun onCreate(savedInstanceState: Bundle?) {        super.onCreate(savedInstanceState)        setContentView(R.layout.activity_main)        dbHelper = DatabaseHelper(this)        recyclerView = findViewById(R.id.recyclerViewClientes)        recyclerView.layoutManager = LinearLayoutManager(this)        cargarClientes()        findViewById<FloatingActionButton>(R.id.fabAgregar).setOnClickListener {            startActivity(Intent(this, AddEditActivity::class.java))        }    }    override fun onResume() {        super.onResume()        cargarClientes()    }    private fun cargarClientes() {        val lista = dbHelper.obtenerClientes()        if (adapter == null) {            adapter = CustomerAdapter(lista, this)            recyclerView.adapter = adapter        } else {            adapter.actualizarLista(lista)        }    }}
